# =============================================================================
# Spatial Grid for efficient proximity queries
# =============================================================================

class SpatialGrid:
    """Grid-based spatial partitioning for efficient neighbor queries."""

    def __init__(self, width: float, height: float, cell_size: float = 50.0):
        self.width = width
        self.height = height
        self.cell_size = cell_size
        self.cols = int(math.ceil(width / cell_size))
        self.rows = int(math.ceil(height / cell_size))
        self.cells: dict[tuple[int, int], set[str]] = defaultdict(set)

    def clear(self):
        self.cells.clear()

    def _get_cell(self, pos: Vector2) -> tuple[int, int]:
        cx = max(0, min(int(pos.x / self.cell_size), self.cols - 1))
        cy = max(0, min(int(pos.y / self.cell_size), self.rows - 1))
        return (cx, cy)

    def insert(self, player_id: str, pos: Vector2):
        cell = self._get_cell(pos)
        self.cells[cell].add(player_id)

    def query_radius(self, pos: Vector2, radius: float) -> set[str]:
        """Return all player IDs within radius of pos."""
        results = set()
        min_cx = max(0, int((pos.x - radius) / self.cell_size))
        max_cx = min(self.cols - 1, int((pos.x + radius) / self.cell_size))
        min_cy = max(0, int((pos.y - radius) / self.cell_size))
        max_cy = min(self.rows - 1, int((pos.y + radius) / self.cell_size))

        for cx in range(min_cx, max_cx + 1):
            for cy in range(min_cy, max_cy + 1):
                results.update(self.cells.get((cx, cy), set()))
        return results


# =============================================================================
# Visibility / Line-of-Sight Engine (SERVER-SIDE - Anti-Wallhack Core)
# =============================================================================

class VisibilityEngine:
    """
    Server-authoritative visibility system.

    THIS IS THE ANTI-WALLHACK CORE:
    - The server computes what each player can see
    - Only visible data is transmitted to each client
    - Clients NEVER receive positions of players they can't see
    - This makes wallhacks impossible because the data simply isn't there
    """

    def __init__(self, obstacles: list[Obstacle]):
        self.obstacles = obstacles
        self._obstacle_segments = self._precompute_segments()

    def _precompute_segments(self) -> list[tuple[Vector2, Vector2]]:
        """Convert obstacle AABBs to line segments for raycasting."""
        segments = []
        for obs in self.obstacles:
            if not obs.blocks_vision:
                continue
            b = obs.bounds
            # Four edges of the AABB
            segments.append((Vector2(b.min_x, b.min_y), Vector2(b.max_x, b.min_y)))
            segments.append((Vector2(b.max_x, b.min_y), Vector2(b.max_x, b.max_y)))
            segments.append((Vector2(b.max_x, b.max_y), Vector2(b.min_x, b.max_y)))
            segments.append((Vector2(b.min_x, b.max_y), Vector2(b.min_x, b.min_y)))
        return segments

    def update_obstacles(self, obstacles: list[Obstacle]):
        """Update obstacle list (e.g., when buildings are destroyed or smoke expires)."""
        self.obstacles = obstacles
        self._obstacle_segments = self._precompute_segments()

    @staticmethod
    def _segments_intersect(p1: Vector2, p2: Vector2, p3: Vector2, p4: Vector2) -> bool:
        """Check if line segment p1-p2 intersects with p3-p4."""
        d1x = p2.x - p1.x
        d1y = p2.y - p1.y
        d2x = p4.x - p3.x
        d2y = p4.y - p3.y

        denom = d1x * d2y - d1y * d2x
        if abs(denom) < 1e-10:
            return False

        t = ((p3.x - p1.x) * d2y - (p3.y - p1.y) * d2x) / denom
        u = ((p3.x - p1.x) * d1y - (p3.y - p1.y) * d1x) / denom

        return 0.0 < t < 1.0 and 0.0 < u < 1.0

    def has_line_of_sight(self, from_pos: Vector2, to_pos: Vector2) -> bool:
        """Check if there's a clear line of sight between two positions."""
        for seg_start, seg_end in self._obstacle_segments:
            if self._segments_intersect(from_pos, to_pos, seg_start, seg_end):
                return False
        return True

    def is_in_smoke(self, pos: Vector2, current_time: float) -> bool:
        """Check if a position is inside an active smoke grenade."""
        for obs in self.obstacles:
            if obs.obstacle_type == ObstacleType.SMOKE:
                if obs.expiry_time and obs.expiry_time > current_time:
                    center = Vector2(
                        (obs.bounds.min_x + obs.bounds.max_x) / 2,
                        (obs.bounds.min_y + obs.bounds.max_y) / 2
                    )
                    if pos.distance_to(center) <= SMOKE_GRENADE_RADIUS:
                        return True
        return False

    def compute_visible_players(
        self,
        viewer: Player,
        all_players: dict[str, Player],
        spatial_grid: SpatialGrid,
        current_time: float
    ) -> dict[str, dict]:
        """
        Compute which players are visible to the viewer.

        Returns a dict of player_id -> sanitized player data.
        This is the KEY anti-wallhack function.
        """
        visible = {}
        viewer_pos = viewer.position

        # If viewer is dead, they see nothing (or spectate mode handled separately)
        if viewer.state == PlayerState.DEAD:
            return visible

        # If viewer is in smoke, severely limit vision
        viewer_in_smoke = self.is_in_smoke(viewer_pos, current_time)

        # Get nearby player candidates from spatial grid
        candidates = spatial_grid.query_radius(viewer_pos, MAX_VIEW_DISTANCE)

        for pid in candidates:
            if pid == viewer.player_id:
                continue

            other = all_players.get(pid)
            if not other or other.state == PlayerState.DEAD:
                continue

            other_pos = other.position
            distance = viewer_pos.distance_to(other_pos)

            if distance > MAX_VIEW_DISTANCE:
                continue

            # Smoke check: if viewer is in smoke, can only see very close players
            if viewer_in_smoke and distance > 5.0:
                continue

            # If target is in smoke, can't see them unless very close
            if self.is_in_smoke(other_pos, current_time) and distance > 5.0:
                continue

            # Line of sight check
            if not self.has_line_of_sight(viewer_pos, other_pos):
                # Player is behind a wall - DO NOT SEND THEIR POSITION
                # This is the anti-wallhack protection
                continue

            # Field of view check (optional, 180 degree forward arc for peripheral vision)
            facing = Vector2(math.cos(viewer.rotation), math.sin(viewer.rotation))
            to_other = (other_pos - viewer_pos).normalize()
            dot = facing.dot(to_other)

            # Players behind you are less visible but still detectable at close range
            if dot < -0.3 and distance > 20.0:
                # Behind the player and far away - not visible
                # (Audio cues would be sent separately)
                continue

            # Build sanitized player data
            player_data = {
                'player_id': pid,
                'state': other.state.name,
                'team_id': other.team_id,
            }

            # Position precision depends on distance (fog of war)
            if distance > FOG_OF_WAR_DISTANCE:
                # Fuzz the position for distant players
                fuzz_x = (hash(f"{pid}{int(current_time * 2)}x") % 100 - 50) / 50.0
                fuzz_y = (hash(f"{pid}{int(current_time * 2)}y") % 100 - 50) / 50.0
                player_data['position'] = {
                    'x': other_pos.x + fuzz_x * POSITION_FUZZING_AMOUNT,
                    'y': other_pos.y + fuzz_y * POSITION_FUZZING_AMOUNT,
                }
                player_data['precision'] = 'low'
            else:
                player_data['position'] = {
                    'x': other_pos.x,
                    'y': other_pos.y,
                }
                player_data['precision'] = 'high'

            # Only send detailed info for close players
            if distance < 50.0:
                player_data['rotation'] = other.rotation
                player_data['is_crouching'] = other.is_crouching
                player_data['equipped_weapon'] = other.equipped_weapon
                player_data['health_visible'] = distance < 10.0  # Only show HP very close

            visible[pid] = player_data

        return visible

    def compute_audible_players(
        self,
        viewer: Player,
        all_players: dict[str, Player],
        spatial_grid: SpatialGrid,
        current_time: float
    ) -> list[dict]:
        """
        Compute audio cues for nearby players (footsteps, gunshots).
        Audio travels through walls but is muffled.
        Provides directional audio without exact position.
        """
        audio_cues = []
        viewer_pos = viewer.position

        candidates = spatial_grid.query_radius(viewer_pos, NEAR_AUDIO_DISTANCE * 2)

        for pid in candidates:
            if pid == viewer.player_id:
                continue

            other = all_players.get(pid)
            if not other or other.state == PlayerState.DEAD:
                continue

            distance = viewer_pos.distance_to(other.position)

            # Footstep sounds
            if other.velocity.length() > 0.1 and distance < NEAR_AUDIO_DISTANCE:
                direction = (other.position - viewer_pos).normalize()
                # Don't give exact position, just direction and rough distance
                volume = max(0.0, 1.0 - distance / NEAR_AUDIO_DISTANCE)
                if other.is_crouching:
                    volume *= 0.3  # Crouching is quieter

                # Check if sound is muffled by walls
                if not self.has_line_of_sight(viewer_pos, other.position):
                    volume *= 0.4  # Muffled through walls

                if volume > 0.05:
                    audio_cues.append({
                        'type': 'footstep',
                        'direction': {'x': direction.x, 'y': direction.y},
                        'volume': round(volume, 2),
                        'distance_band': 'near' if distance < 15 else 'mid' if distance < 30 else 'far'
                    })

            # Gunshot sounds (louder, travel further)
            if current_time - other.last_shot_time < 0.1 and distance < NEAR_AUDIO_DISTANCE * 3:
                direction = (other.position - viewer_pos).normalize()
                volume = max(0.0, 1.0 - distance / (NEAR_AUDIO_DISTANCE * 3))
                audio_cues.append({
                    'type': 'gunshot',
                    'direction': {'x': direction.x, 'y': direction.y},
                    'volume': round(volume, 2),
                    'distance_band': 'near' if distance < 30 else 'mid' if distance < 80 else 'far'
                })

        return audio_cues


# =============================================================================
# Game State Manager
# =============================================================================

class GameState:
    def __init__(self):
        self.players: dict[str, Player] = {}
        self.obstacles: list[Obstacle] = []
        self.projectiles: list[Projectile] = []
        self.loot_items: list[LootItem] = []
        self.zone = ZoneCircle(
            center=Vector2(MAP_WIDTH / 2, MAP_HEIGHT / 2),
            radius=MAP_WIDTH / 2,
            target_radius=MAP_WIDTH / 2,
            shrink_rate=ZONE_SHRINK_RATE,
            damage_per_tick=ZONE_DAMAGE_PER_TICK
        )
        self.phase = GamePhase.WAITING
        self.tick_number: int = 0
        self.start_time: float = 0.0
        self.spatial_grid = SpatialGrid(MAP_WIDTH, MAP_HEIGHT)
        self.visibility_engine: Optional[VisibilityEngine] = None
        self.next_projectile_id = 0
        self.next_obstacle_id = 0
        self.events: list[dict] = []  # Events to broadcast this tick
        self._generate_map()

    def _generate_map(self):
        """Generate map obstacles (buildings, walls, rocks, trees)."""
        import random
        rng = random.Random(42)  # Deterministic map

        obstacle_id = 0

        # Generate buildings
        for _ in range(30):
            x = rng.uniform(100, MAP_WIDTH - 100)
            y = rng.uniform(100, MAP_HEIGHT - 100)
            w = rng.uniform(20, 60)
            h = rng.uniform(20, 60)

            # Building walls (4 walls with gaps for doors)
            walls = [
                # North wall
                AABB(x, y, x + w, y + WALL_THICKNESS),
                # South wall
                AABB(x, y + h - WALL_THICKNESS, x + w, y + h),
                # West wall (with door gap)
                AABB(x, y, x + WALL_THICKNESS, y + h * 0.4),
                AABB(x, y + h * 0.6, x + WALL_THICKNESS, y + h),
                # East wall
                AABB(x + w - WALL_THICKNESS, y, x + w, y + h),
            ]

            for wall_bounds in walls:
                self.obstacles.append(Obstacle(
                    obstacle_id=obstacle_id,
                    obstacle_type=ObstacleType.BUILDING,
                    bounds=wall_bounds,
                    blocks_vision=True,
                    blocks_movement=True
                ))
                obstacle_id += 1

        # Generate rocks
        for _ in range(50):
            x = rng.uniform(50, MAP_WIDTH - 50)
            y = rng.uniform(50, MAP_HEIGHT - 50)
            size = rng.uniform(3, 8)
            self.obstacles.append(Obstacle(
                obstacle_id=obstacle_id,
                obstacle_type=ObstacleType.ROCK,
                bounds=AABB(x - size, y - size, x + size, y + size),
                blocks_vision=True,
                blocks_movement=True
            ))
            obstacle_id += 1

        # Generate trees (block vision but not movement)
        for _ in range(100):
            x = rng.uniform(50, MAP_WIDTH - 50)
            y = rng.uniform(50, MAP_HEIGHT - 50)
            size = rng.uniform(2, 4)
            self.obstacles.append(Obstacle(
                obstacle_id=obstacle_id,
                obstacle_type=ObstacleType.TREE,
                bounds=AABB(x - size, y - size, x + size, y + size),
                blocks_vision=True,
                blocks_movement=False
            ))
            obstacle_id += 1

        self.next_obstacle_id = obstacle_id
        self.visibility_engine = VisibilityEngine(self.obstacles)

    def add_player(self, player_id: str, team_id: Optional[int] = None) -> Player:
        import random
        spawn_x = random.uniform(100, MAP_WIDTH - 100)
        spawn_y = random.uniform(100, MAP_HEIGHT - 100)
        player = Player(
            player_id=player_id,
            position=Vector2(spawn_x, spawn_y),
            team_id=team_id
        )
        self.players[player_id] = player
        return player

    def remove_player(self, player_id: str):
        self.players.pop(player_id, None)

    def update_spatial_grid(self):
        self.spatial_grid.clear()
        for pid, player in self.players.items():
            if player.state != PlayerState.DEAD:
                self.spatial_grid.insert(pid, player.position)

    def update_zone(self, current_time: float):
        """Shrink the zone over time."""
        if self.phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            if self.zone.radius > self.zone.target_radius:
                self.zone.radius = max(
                    self.zone.target_radius,
                    self.zone.radius - self.zone.shrink_rate * TICK_INTERVAL
                )

            # Apply zone damage
            for player in self.players.values():
                if player.state == PlayerState.ALIVE:
                    dist = player.position.distance_to(self.zone.center)
                    if dist > self.zone.radius:
                        player.health -= self.zone.damage_per_tick * TICK_INTERVAL
                        if player.health <= 0:
                            player.health = 0
                            player.state = PlayerState.DEAD
                            self.events.append({
                                'type': 'player_eliminated',
                                'player_id': player.player_id,
                                'cause': 'zone'
                            })

    def update_projectiles(self, current_time: float):
        """Update projectile positions and check collisions."""
        remaining = []
        for proj in self.projectiles:
            # Move projectile
            proj.position.x += proj.velocity.x * TICK_INTERVAL
            proj.position.y += proj.velocity.y * TICK_INTERVAL

            # Check range
            if proj.origin.distance_to(proj.position) > proj.max_range:
                continue

            # Check out of bounds
            if not (0 <= proj.position.x <= MAP_WIDTH and 0 <= proj.position.y <= MAP_HEIGHT):
                continue

            # Check obstacle collision
            hit_obstacle = False
            for obs in self.obstacles:
                if obs.blocks_movement and obs.bounds.contains_point(proj.position):
                    hit_obstacle = True
                    break
            if hit_obstacle:
                continue

            # Check player collision
            hit_player = False
            candidates = self.spatial_grid.query_radius(proj.position, PLAYER_RADIUS * 2)
            for pid in candidates:
                if pid == proj.owner_id:
                    continue
                player = self.players.get(pid)
                if not player or player.state != PlayerState.ALIVE:
                    continue
                if proj.position.distance_to(player.position) < PLAYER_RADIUS * 2:
                    # Hit!
                    actual_damage = proj.damage
                    if player.shield > 0:
                        shield_absorb = min(player.shield, actual_damage * 0.5)
                        player.shield -= shield_absorb
                        actual_damage -= shield_absorb

                    player.health -= actual_damage
                    owner = self.players.get(proj.owner_id)
                    if owner:
                        owner.damage_dealt += actual_damage

                    if player.health <= 0:
                        player.health = 0
                        player.state = PlayerState.DEAD
                        if owner:
                            owner.kills += 1
                        self.events.append({
                            'type': 'player_eliminated',
                            'player_id': pid,
                            'killer_id': proj.owner_id,
                            'cause': 'projectile'
                        })

                    self.events.append({
                        'type': 'hit_marker',
                        'target_id': pid,
                        'shooter_id': proj.owner_id,
                        'damage': actual_damage,
                        'position': {'x': proj.position.x, 'y': proj.position.y}
                    })
                    hit_player = True
                    break

            if not hit_player:
                remaining.append(proj)

        self.projectiles = remaining

    def cleanup_expired_obstacles(self, current_time: float):
        """Remove expired smoke grenades etc."""
        before = len(self.obstacles)
        self.obstacles = [
            obs for obs in self.obstacles
            if obs.expiry_time is None or obs.expiry_time > current_time
        ]
        if len(self.obstacles) != before:
            self.visibility_engine.update_obstacles(self.obstacles)

    def check_win_condition(self) -> Optional[dict]:
        """Check if the game has a winner."""
        alive_players = [p for p in self.players.values() if p.state == PlayerState.ALIVE]

        if len(alive_players) <= 1:
            if alive_players:
                winner = alive_players[0]
                return {
                    'type': 'game_over',
                    'winner_id': winner.player_id,
                    'winner_team': winner.team_id
                }
            else:
                return {'type': 'game_over', 'winner_id': None}
        return None


