# Input Validation & Anti-Cheat
# =============================================================================

class InputValidator:
    """Server-side input validation to prevent cheating."""

    @staticmethod
    def validate_movement(player: Player, dx: float, dy: float) -> tuple[float, float]:
        """Validate and clamp movement input."""
        # Clamp to maximum speed
        speed = math.sqrt(dx * dx + dy * dy)
        if speed > MAX_SPEED:
            scale = MAX_SPEED / speed
            dx *= scale
            dy *= scale

        # Reduce speed if crouching
        if player.is_crouching:
            dx *= 0.5
            dy *= 0.5

        return dx, dy

    @staticmethod
    def validate_rotation(rotation: float) -> float:
        """Normalize rotation to [0, 2*pi)."""
        return rotation % (2 * math.pi)

    @staticmethod
    def check_rate_limit(player: Player, current_time: float) -> bool:
        """Check if player is sending too many actions (speed hack detection)."""
        if current_time - player.action_window_start > 1.0:
            player.action_window_start = current_time
            player.action_count = 0

        player.action_count += 1
        if player.action_count > RATE_LIMIT_ACTIONS_PER_SECOND:
            logger.warning(f"Rate limit exceeded for player {player.player_id}")
            return False
        return True

    @staticmethod
    def validate_position_bounds(pos: Vector2) -> Vector2:
        """Clamp position to map bounds."""
        pos.x = max(0, min(MAP_WIDTH, pos.x))
        pos.y = max(0, min(MAP_HEIGHT, pos.y))
        return pos

    @staticmethod
    def check_collision_with_obstacles(
        old_pos: Vector2, new_pos: Vector2, obstacles: list[Obstacle]
    ) -> Vector2:
        """Check movement against obstacles and resolve collisions."""
        for obs in obstacles:
            if not obs.blocks_movement:
                continue
            if obs.bounds.contains_point(new_pos):
                # Simple collision resolution: revert to old position
                # A more sophisticated system would slide along walls
                return old_pos
        return new_pos


# =============================================================================
# Encrypted Communication Layer
# =============================================================================

class SecureChannel:
    """
    Encrypted communication using X25519 key exchange + AES-256-GCM.
    Prevents packet sniffing and man-in-the-middle attacks.
    """

    def __init__(self):
        self.server_private_key = x25519.X25519PrivateKey.generate()
        self.server_public_key = self.server_private_key.public_key()

    def get_server_public_key_bytes(self) -> bytes:
        return self.server_public_key.public_bytes(
            encoding=serialization.Encoding.Raw,
            format=serialization.PublicFormat.Raw
        )

    def derive_session_key(self, client_public_key_bytes: bytes) -> tuple[bytes, AESGCM]:
        """Derive a shared session key from client's public key."""
        client_public_key = x25519.X25519PublicKey.from_public_bytes(client_public_key_bytes)
        shared_secret = self.server_private_key.exchange(client_public_key)

        # Derive encryption key using HKDF
        session_key = HKDF(
            algorithm=hashes.SHA256(),
            length=32,
            salt=None,
            info=b'battle-royale-session-v1',
        ).derive(shared_secret)

        aesgcm = AESGCM(session_key)
        return session_key, aesgcm

    @staticmethod
    def encrypt_message(aesgcm: AESGCM, nonce_counter: int, plaintext: bytes) -> bytes:
        """Encrypt a message with AES-256-GCM."""
        # Use counter-based nonce (12 bytes)
        nonce = struct.pack('>Q', nonce_counter).rjust(12, b'\x00')
        ciphertext = aesgcm.encrypt(nonce, plaintext, None)
        return struct.pack('>I', len(ciphertext) + 12) + nonce + ciphertext

    @staticmethod
    def decrypt_message(aesgcm: AESGCM, data: bytes) -> Optional[bytes]:
        """Decrypt a message with AES-256-GCM."""
        if len(data) < 12:
            return None
        nonce = data[:12]
        ciphertext = data[12:]
        try:
            return aesgcm.decrypt(nonce, ciphertext, None)
        except Exception:
            return None


# =============================================================================
# Game Server
# =============================================================================

class BattleRoyaleServer:
    def __init__(self, host: str = '0.0.0.0', port: int = 7777):
        self.host = host
        self.port = port
        self.game_state = GameState()
        self.connections: dict[str, ClientConnection] = {}
        self.secure_channel = SecureChannel()
        self.input_validator = InputValidator()
        self.running = False
        self.server_token = secrets.token_hex(32)
        self._lock = asyncio.Lock()

    async def start(self):
        """Start the game server."""
        server = await asyncio.start_server(
            self._handle_client, self.host, self.port
        )
        self.running = True
        logger.info(f"Battle Royale Server started on {self.host}:{self.port}")
        logger.info(f"Server public key: {self.secure_channel.get_server_public_key_bytes().hex()}")

        # Start game loop
        asyncio.create_task(self._game_loop())

        async with server:
            await server.serve_forever()

    async def _handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        """Handle a new client connection."""
        addr = writer.get_extra_info('peername')
        logger.info(f"New connection from {addr}")

        player_id = secrets.token_hex(16)
        conn = ClientConnection(
            player_id=player_id,
            reader=reader,
            writer=writer,
            last_heartbeat=time.time()
        )

        try:
            # Perform key exchange
            await self._perform_key_exchange(conn)

            if not conn.authenticated:
                logger.warning(f"Authentication failed for {addr}")
                writer.close()
                await writer.wait_closed()
                return

            # Add player to game
            async with self._lock:
                self.connections[player_id] = conn
                player = self.game_state.add_player(player_id)

            logger.info(f"Player {player_id} joined from {addr}")

            # Send initial game state (map data, zone info - no other player positions)
            await self._send_initial_state(conn)

            # Handle client messages
            await self._client_message_loop(conn)

        except (asyncio.IncompleteReadError, ConnectionResetError, ConnectionError) as e:
            logger.info(f"Client {player_id} disconnected: {e}")
        except Exception as e:
            logger.error(f"Error handling client {player_id}: {e}", exc_info=True)
        finally:
            async with self._lock:
                self.connections.pop(player_id, None)
                self.game_state.remove_player(player_id)
            try:
                writer.close()
                await writer.wait_closed()
            except Exception:
                pass
            logger.info(f"Player {player_id} removed")

    async def _perform_key_exchange(self, conn: ClientConnection):
        """Perform X25519 key exchange with client."""
        # Send server public key
        server_pub = self.secure_channel.get_server_public_key_bytes()
        header = struct.pack('>I', len(server_pub))
        conn.writer.write(header + server_pub)
        await conn.writer.drain()

        # Receive client public key (32 bytes for X25519)
        try:
            length_data = await asyncio.wait_for(conn.reader.readexactly(4), timeout=10.0)
            length = struct.unpack('>I', length_data)[0]
            if length != 32:
                return
            client_pub_bytes = await asyncio.wait_for(conn.reader.readexactly(length), timeout=10.0)
        except (asyncio.TimeoutError, asyncio.IncompleteReadError):
            return

        # Derive session key
        try:
            session_key, aesgcm = self.secure_channel.derive_session_key(client_pub_bytes)
            conn.session_key = session_key
            conn.aesgcm = aesgcm
            conn.authenticated = True

            # Send encrypted confirmation with player_id
            confirm_msg = json.dumps({
                'type': 'auth_success',
                'player_id': conn.player_id,
            }).encode()
            await self._send_encrypted(conn, confirm_msg)

        except Exception as e:
            logger.error(f"Key exchange failed: {e}")

    async def _send_encrypted(self, conn: ClientConnection, data: bytes):
        """Send an encrypted message to a client."""
        if not conn.aesgcm:
            return
        conn.nonce_counter += 1
        encrypted = SecureChannel.encrypt_message(conn.aesgcm, conn.nonce_counter, data)
        conn.writer.write(encrypted)
        await conn.writer.drain()

    async def _recv_encrypted(self, conn: ClientConnection) -> Optional[bytes]:
        """Receive and decrypt a message from a client."""
        if not conn.aesgcm:
            return None
        try:
            length_data = await asyncio.wait_for(conn.reader.readexactly(4), timeout=30.0)
            length = struct.unpack('>I', length_data)[0]
            if length > 65536:  # Max message size
                return None
            encrypted_data = await asyncio.wait_for(conn.reader.readexactly(length), timeout=30.0)
            return SecureChannel.decrypt_message(conn.aesgcm, encrypted_data)
        except (asyncio.TimeoutError, asyncio.IncompleteReadError):
            return None

    async def _send_initial_state(self, conn: ClientConnection):
        """Send initial game state to a newly connected player."""
        # Send map layout (obstacles are public knowledge)
        obstacles_data = []
        for obs in self.game_state.obstacles:
            obstacles_data.append({
                'id': obs.obstacle_id,
                'type': obs.obstacle_type.name,
                'bounds': {
                    'min_x': obs.bounds.min_x,
                    'min_y': obs.bounds.min_y,
                    'max_x': obs.bounds.max_x,
                    'max_y': obs.bounds.max_y,
                },
                'blocks_vision': obs.blocks_vision,
                'blocks_movement': obs.blocks_movement,
            })

        player = self.game_state.players[conn.player_id]
        initial_state = {
            'type': 'initial_state',
            'map': {
                'width': MAP_WIDTH,
                'height': MAP_HEIGHT,
                'obstacles': obstacles_data,
            },
            'zone': {
                'center': {'x': self.game_state.zone.center.x, 'y': self.game_state.zone.center.y},
                'radius': self.game_state.zone.radius,
                'target_radius': self.game_state.zone.target_radius,
            },
            'your_position': {'x': player.position.x, 'y': player.position.y},
            'phase': self.game_state.phase.name,
            'tick_rate': TICK_RATE,
            'player_count': len([p for p in self.game_state.players.values()
                                if p.state == PlayerState.ALIVE]),
        }

        await self._send_encrypted(conn, json.dumps(initial_state).encode())

    async def _client_message_loop(self, conn: ClientConnection):
        """Process messages from a client."""
        while self.running:
            data = await self._recv_encrypted(conn)
            if data is None:
                break

            conn.last_heartbeat = time.time()

            try:
                message = json.loads(data.decode())
            except (json.JSONDecodeError, UnicodeDecodeError):
                logger.warning(f"Invalid message from {conn.player_id}")
                continue

            await self._process_client_message(conn, message)

    async def _process_client_message(self, conn: ClientConnection, message: dict):
        """Process a validated client message."""
        msg_type = message.get('type')
        current_time = time.time()

        player = self.game_state.players.get(conn.player_id)
        if not player:
            return

        # Rate limiting
        if not self.input_validator.check_rate_limit(player, current_time):
            await self._send_encrypted(conn, json.dumps({
                'type': 'error',
                'message': 'rate_limited'
            }).encode())
            return

        if msg_type == 'move':
            await self._handle_move(player, message)
        elif msg_type == 'rotate':
            await self._handle_rotate(player, message)
        elif msg_type == 'shoot':
            await self._handle_shoot(player, message, current_time)
        elif msg_type == 'crouch':
            player.is_crouching = message.get('crouching', False)
        elif msg_type == 'use_item':
            await self._handle_use_item(player, message, current_time)
        elif msg_type == 'heartbeat':
            conn.last_heartbeat = current_time
        elif msg_type == 'ping':
            await self._send_encrypted(conn, json.dumps({
                'type': 'pong',
                'client_time': message.get('client_time'),
                'server_time': current_time
            }).encode())

    async def _handle_move(self, player: Player, message: dict):
        """Handle player movement with server-side validation."""
        if player.state != PlayerState.ALIVE:
            return

        dx = float(message.get('dx', 0))
        dy = float(message.get('dy', 0))

        # Validate movement
        dx, dy = self.input_validator.validate_movement(player, dx, dy)

        old_pos = Vector2(player.position.x, player.position.y)
        new_pos = Vector2(
            player.position.x + dx * TICK_INTERVAL,
            player.position.y + dy * TICK_INTERVAL
        )

        # Bounds check
        new_pos = self.input_validator.validate_position_bounds(new_pos)

        # Collision check
        new_pos = self.input_validator.check_collision_with_obstacles(
            old_pos, new_pos, self.game_state.obstacles
        )

        player.position = new_pos
        player.velocity = Vector2(dx, dy)

    async def _handle_rotate(self, player: Player, message: dict):
        """Handle player rotation."""
        rotation = float(message.get('rotation', 0))
        player.rotation = self.input_validator.validate_rotation(rotation)

    async def _handle_shoot(self, player: Player, message: dict, current_time: float):
        """Handle shooting with server-side hit detection."""
        if player.state != PlayerState.ALIVE:
            return

        # Weapon cooldown check
        weapon_cooldown = 0.1  # 100ms between shots (adjust per weapon)
        if current_time - player.last_shot_time < weapon_cooldown:
            return

        player.last_shot_time = current_time

        # Create projectile from player's position in their facing direction
        direction = Vector2(
            math.cos(player.rotation),
            math.sin(player.rotation)
        )

        projectile = Projectile(
            projectile_id=self.game_state.next_projectile_id,
            owner_id=player.player_id,
            position=Vector2(
                player.position.x + direction.x * 2,
                player.position.y + direction.y * 2
            ),
            velocity=direction * BULLET_SPEED,
            damage=25.0,
            created_at=current_time,
            origin=Vector2(player.position.x, player.position.y)
        )
        self.game_state.next_projectile_id += 1
        self.game_state.projectiles.append(projectile)

        # Add gunshot event (visible/audible to nearby players)
        self.game_state.events.append({
            'type': 'gunshot',
            'player_id': player.player_id,
            'position': {'x': player.position.x, 'y': player.position.y},
            'direction': {'x': direction.x, 'y': direction.y}
        })

    async def _handle_use_item(self, player: Player, message: dict, current_time: float):
        """Handle item usage (smoke grenades, heals, etc.)."""
        item_type = message.get('item_type')

        if item_type == 'smoke_grenade':
            target_x = float(message.get('target_x', player.position.x))
            target_y = float(message.get('target_y', player.position.y))

            # Validate throw distance
            target = Vector2(target_x, target_y)
            if player.position.distance_to(target) > 50.0:
                return

            # Create smoke obstacle
            smoke = Obstacle(
                obstacle_id=self.game_state.next_obstacle_id,
                obstacle_type=ObstacleType.SMOKE,
                bounds=AABB(
                    target_x - SMOKE_GRENADE_RADIUS,
                    target_y - SMOKE_GRENADE_RADIUS,
                    target_x + SMOKE_GRENADE_RADIUS,
                    target_y + SMOKE_GRENADE_RADIUS
                ),
                blocks_vision=True,
                blocks_movement=False,
                expiry_time=current_time + 15.0  # 15 second smoke
            )
            self.game_state.next_obstacle_id += 1
            self.game_state.obstacles.append(smoke)
            self.game_state.visibility_engine.update_obstacles(self.game_state.obstacles)

            self.game_state.events.append({
                'type': 'smoke_deployed',
                'position': {'x': target_x, 'y': target_y},
                'expiry_time': current_time + 15.0
            })

        elif item_type == 'heal':
            if player.health < MAX_HEALTH:
                player.health = min(MAX_HEALTH, player.health + 25)

    # =========================================================================
    # Main Game Loop
    # =========================================================================

    async def _game_loop(self):
        """Server authoritative game loop running at TICK_RATE Hz."""
        logger.info(f"Game loop started at {TICK_RATE} Hz")

        while self.running:
            tick_start = time.time()
            current_time = tick_start

            async with self._lock:
                self.game_state.tick_number += 1
                self.game_state.events.clear()

                # Update spatial grid
                self.game_state.update_spatial_grid()

                # Update zone
                self.game_state.update_zone(current_time)

                # Update projectiles
                self.game_state.update_projectiles(current_time)

                # Cleanup expired obstacles
                self.game_state.cleanup_expired_obstacles(current_time)

                # Check win condition
                win_result = self.game_state.check_win_condition()
                if win_result:
                    self.game_state.events.append(win_result)

                # Send per-player visibility-filtered state to each client
                await self._broadcast_game_state(current_time)

            # Sleep until next tick
            elapsed = time.time() - tick_start
            sleep_time = max(0, TICK_INTERVAL - elapsed)
            if sleep_time > 0:
                await asyncio.sleep(sleep_time)
            elif elapsed > TICK_INTERVAL * 2:
                logger.warning(f"Tick {self.game_state.tick_number} took {elapsed*1000:.1f}ms "
                             f"(budget: {TICK_INTERVAL*1000:.1f}ms)")

    async def _broadcast_game_state(self, current_time: float):
        """
        Send VISIBILITY-FILTERED game state to each client.

        THIS IS THE CORE ANTI-WALLHACK MECHANISM:
        Each client receives ONLY the data they are allowed to see.
        Players behind walls are NOT included in the update.
        """
        gs = self.game_state
        ve = gs.visibility_engine

        # Pre-compute common data
        zone_data = {
            'center': {'x': gs.zone.center.x, 'y': gs.zone.center.y},
            'radius': gs.zone.radius,
            'target_radius': gs.zone.target_radius,
        }

        alive_count = len([p for p in gs.players.values() if p.state == PlayerState.ALIVE])

        # Global events that everyone should see (eliminations, zone updates)
        global_events = [
            e for e in gs.events
            if e['type'] in ('player_eliminated', 'game_over', 'zone_update')
        ]

        send_tasks = []

        for player_id, conn in self.connections.items():
            if not conn.authenticated:
                continue

            player = gs.players.get(player_id)
            if not player:
                continue

            # ============================================================
            # SERVER-SIDE VISIBILITY FILTERING (Anti-Wallhack)
            # ============================================================
            # Compute what THIS specific player can see
            visible_players = ve.compute_visible_players(
                player, gs.players, gs.spatial_grid, current_time
            )

            # Compute audio cues (directional, no exact positions)
            audio_cues = ve.compute_audible_players(
                player, gs.players, gs.spatial_grid, current_time
            )

            # Filter events to only those relevant/visible to this player
            player_events = list(global_events)
            for event in gs.events:
                if event['type'] == 'gunshot':
                    # Only send gunshot if player can see or hear it
                    evt_pos = Vector2(event['position']['x'], event['position']['y'])
                    dist = player.position.distance_to(evt_pos)
                    if dist < NEAR_AUDIO_DISTANCE * 3:
                        # Send direction and distance band, not exact position
                        direction = (evt_pos - player.position).normalize()
                        player_events.append({
                            'type': 'gunshot_audio',
                            'direction': {'x': direction.x, 'y': direction.y},
                            'distance_band': 'near' if dist < 30 else 'mid' if dist < 80 else 'far'
                        })
                    if event['player_id'] in visible_players:
                        player_events.append(event)

                elif event['type'] == 'hit_marker':
                    if event['shooter_id'] == player_id:
                        player_events.append({
                            'type': 'hit_confirm',
                            'damage': event['damage']
                        })

                elif event['type'] == 'smoke_deployed':
                    # Smoke is visible to everyone nearby
                    smoke_pos = Vector2(event['position']['x'], event['position']['y'])
                    if player.position.distance_to(smoke_pos) < MAX_VIEW_DISTANCE:
                        player_events.append(event)

            # Filter visible projectiles (only those the player can see)
            visible_projectiles = []
            for proj in gs.projectiles:
                dist = player.position.distance_to(proj.position)
                if dist < MAX_VIEW_DISTANCE:
                    if ve.has_line_of_sight(player.position, proj.position):
                        visible_projectiles.append({
                            'position': {'x': proj.position.x, 'y': proj.position.y},
                            'velocity': {'x': proj.velocity.x, 'y': proj.velocity.y},
                        })

            # Build the per-player state update
            state_update = {
                'type': 'state_update',
                'tick': gs.tick_number,
                'timestamp': current_time,
                'your_state': {
                    'position': {'x': player.position.x, 'y': player.position.y},
                    'rotation': player.rotation,
                    'health': player.health,
                    'shield': player.shield,
                    'state': player.state.name,
                    'kills': player.kills,
                    'is_crouching': player.is_crouching,
                },
                # ONLY visible players - wallhack impossible
                'visible_players': visible_players,
                'audio_cues': audio_cues,
                'visible_projectiles': visible_projectiles,
                'zone': zone_data,
                'alive_count': alive_count,
                'events': player_events,
                'phase': gs.phase.name,
            }

            data = json.dumps(state_update, separators=(',', ':')).encode()
            send_tasks.append(self._send_encrypted(conn, data))

        # Send all updates concurrently
        if send_tasks:
            results = await asyncio.gather(*send_tasks, return_exceptions=True)
            for i, result in enumerate(results):
                if isinstance(result, Exception):
                    logger.debug(f"Failed to send update: {result}")

    async def _disconnect_inactive_clients(self, current_time: float, timeout: float = 30.0):
        """Disconnect clients that haven't sent a heartbeat."""
        to_remove = []
        for pid, conn in self.connections.items():
            if current_time - conn.last_heartbeat > timeout:
                to_remove.append(pid)

        for pid in to_remove:
            conn = self.connections.pop(pid, None)
            if conn:
                try:
                    conn.writer.close()
                    await conn.writer.wait_closed()
                except Exception:
                    pass
                self.game_state.remove_player(pid)
                logger.info(f"Disconnected inactive player {pid}")


# =============================================================================
# Demo Client (for testing)
# =============================================================================

class DemoClient:
    """Simple demo client for testing the server."""

    def __init__(self, host: str = '127.0.0.1', port: int = 7777):
        self.host = host
        self.port = port
        self.player_id: Optional[str] = None
        self.aesgcm: Optional[AESGCM] = None
        self.nonce_counter = 0
        self.reader: Optional[asyncio.StreamReader] = None
        self.writer: Optional[asyncio.StreamWriter] = None

    async def connect(self):
        """Connect to the server and perform key exchange."""
        self.reader, self.writer = await asyncio.open_connection(self.host, self.port)

        # Receive server public key
        length_data = await self.reader.readexactly(4)
        length = struct.unpack('>I', length_data)[0]
        server_pub_bytes = await self.reader.readexactly(length)

        # Generate client key pair
        client_private = x25519.X25519PrivateKey.generate()
        client_public = client_private.public_key()
        client_pub_bytes = client_public.public_bytes(
            encoding=serialization.Encoding.Raw,
            format=serialization.PublicFormat.Raw
        )

        # Send client public key
        self.writer.write(struct.pack('>I', len(client_pub_bytes)) + client_pub_bytes)
        await self.writer.drain()

        # Derive session key
        server_pub_key = x25519.X25519PublicKey.from_public_bytes(server_pub_bytes)
        shared_secret = client_private.exchange(server_pub_key)
        session_key = HKDF(
            algorithm=hashes.SHA256(),
            length=32,
            salt=None,
            info=b'battle-royale-session-v1',
        ).derive(shared_secret)
        self.aesgcm = AESGCM(session_key)

        # Receive auth confirmation
        auth_msg = await self._recv_encrypted()
        if auth_msg:
            auth_data = json.loads(auth_msg.decode())
            self.player_id = auth_data.get('player_id')
            logger.info(f"Client authenticated as {self.player_id}")

        # Receive initial state
        initial_state = await self._recv_encrypted()
        if initial_state:
            state = json.loads(initial_state.decode())
            logger.info(f"Received initial state: phase={state.get('phase')}, "
                       f"player_count={state.get('player_count')}")

        return self.player_id is not None

    async def _send_encrypted(self, data: bytes):
        self.nonce_counter += 1
        encrypted = SecureChannel.encrypt_message(self.aesgcm, self.nonce_counter, data)
        self.writer.write(encrypted)
        await self.writer.drain()

    async def _recv_encrypted(self) -> Optional[bytes]:
        try:
            length_data = await asyncio.wait_for(self.reader.readexactly(4), timeout=10.0)
            length = struct.unpack('>I', length_data)[0]
            encrypted_data = await asyncio.wait_for(self.reader.readexactly(length), timeout=10.0)
            return SecureChannel.decrypt_message(self.aesgcm, encrypted_data)
        except Exception:
            return None

    async def send_move(self, dx: float, dy: float):
        msg = json.dumps({'type': 'move', 'dx': dx, 'dy': dy}).encode()
        await self._send_encrypted(msg)

    async def send_rotate(self, rotation: float):
        msg = json.dumps({'type': 'rotate', 'rotation': rotation}).encode()
        await self._send_encrypted(msg)

    async def send_shoot(self):
        msg = json.dumps({'type': 'shoot'}).encode()
        await self._send_encrypted(msg)

    async def receive_update(self) -> Optional[dict]:
        data = await self._recv_encrypted()
        if data:
            return json.loads(data.decode())
        return None

    async def game_loop(self):
        """Simple client game loop for demonstration."""
        import random

        move_angle = random.uniform(0, 2 * math.pi)
        tick = 0

        while True:
            try:
                # Send movement
                dx = math.cos(move_angle) * 5.0
                dy = math.sin(move_angle) * 5.0
                await self.send_move(dx, dy)
                await self.send_rotate(move_angle)

                # Occasionally change direction
                if tick % 100 == 0:
                    move_angle = random.uniform(0, 2 * math.pi)

                # Occasionally shoot
                if tick % 50 == 0:
                    await self.send_shoot()

                # Receive state update
                update = await self.receive_update()
                if update and update.get('type') == 'state_update':
                    visible_count = len(update.get('visible_players', {}))
                    my_state = update.get('your_state', {})
                    if tick % 64 == 0:  # Log once per second
                        logger.info(
                            f"[Client {self.player_id[:8]}] "
                            f"Pos=({my_state.get('position', {}).get('x', 0):.0f}, "
                            f"{my_state.get('position', {}).get('y', 0):.0f}) "
                            f"HP={my_state.get('health', 0):.0f} "
                            f"Visible={visible_count} "
                            f"Alive={update.get('alive_count', 0)} "
                            f"Audio={len(update.get('audio_cues', []))}"
                        )

                tick += 1
                await asyncio.sleep(TICK_INTERVAL)

            except Exception as e:
                logger.error(f"Client error: {e}")
                break

    async def disconnect(self):
        if self.writer:
            self.writer.close()
            await self.writer.wait_closed()


